connection_mgr__bluetooth__pairing__connection__text = TextObject(bs_BA="Veza se uspostavlja. Sačekajte...", cs_CZ="Spojení se navazuje. Čekejte prosím...", da_DK="Der oprettes forbindelse. Vent...", de_DE="Die Verbindung wird hergestellt. Bitte warten...", el_GR="Δημιουργείται η σύνδεση. Παρακαλώ περιμένετε...", en_GB="Establishing connection. Please wait...", es_ES="Estableciendo la conexión. Por favor, espere...", fi_FI="Yhteys muodostuu. Odota...", fr_FR="Établissement de la connexion en cours. Veuillez\npatienter...", hr_HR="Veza se uspostavlja. Čekajte...", hu_HU="Kapcsolat létrehozása. Kérem, várjon...", it_IT="Collegamento in corso. Attendere prego...", nl_NL="De verbinding wordt opgebouwd. Wachten a.u.b...", no_NO="Oppretter forbindelse. Vent litt...", pl_PL="Nawiązywanie połączenia. Proszę czekać...", pt_PT="A estabelecer a ligação. Por favor, aguarde...", ro_RO="Se realizează conexiunea. Aşteptaţi...", ru_RU="Установление соединения. Пожалуйста, ждите...", sk_SK="Spojenie sa vytvára. Čakajte, prosím...", sl_SI="Povezava se vzpostavlja. Prosimo, počakajte ...", sr_RS="Veza se uspostavlja. Molimo sačekajte...", sv_SE="Anslutningen upprättas. Var god vänta...", tr_TR="Bağlantı kuruluyor. Lütfen bekleyin...", uk_UA="Встановлюється з’єднання. Зачекайте...")
connection_mgr__bluetooth__pairing__no_device_found__text = TextObject(bs_BA="Nisu pronađeni uređaji.", cs_CZ="Nebyla nalezena žádná zařízení.", da_DK="Ingen apparater fundet", de_DE="Es wurden keine Geräte gefunden.", el_GR="Δεν βρέθηκαν συσκευές.", en_GB="No devices were found.", es_ES="No se han encontrado dispositivos.", fi_FI="Laitteita ei löytynyt.", fr_FR="Aucun périphérique n'a été trouvé.", hr_HR="Nisu pronađeni nikakvi uređaji.", hu_HU="Nem találhatók készülékek.", it_IT="Non è stato trovato nessun dispositivo.", nl_NL="Er zijn geen apparaten gevonden.", no_NO="Finner ingen enheter.", pl_PL="Nie znaleziono urządzeń.", pt_PT="Não foram encontrados aparelhos.", ro_RO="Nu s-au găsit dispozitive.", ru_RU="Устройства не найдены.", sk_SK="Nenašli sa žiadne prístroje.", sl_SI="Ni najdenih naprav.", sr_RS="Nije pronađen nijedan uređaj.", sv_SE="Inga enheter hittades.", tr_TR="Hiçbir cihaz bulunamadı.", uk_UA="Не знайдено жодного пристрою.")
connection_mgr__bluetooth__pairing__search_with_vehicle_name__text = TextObject(bs_BA="Naziv vozila: %1  Uvjerite se da je\nBluetooth uključen na Vašem uređaju i da je\naktivirana vidljivost.", cs_CZ="Jméno vozidla: %1  Zkontrolujte\nprosím, že je Bluetooth ve Vašem zařízení zapnutý a\nbyla aktivována viditelnost.", da_DK="Bilens navn: %1  Kontroller, at\nBluetooth er aktiveret på dit apparat, og at\nsynligheden er aktiveret.", de_DE="Fahrzeugname: %1  Bitte stelle\nsicher, dass Bluetooth an deinem Gerät\neingeschaltet ist und die Sichtbarkeit aktiviert\nwurde.", el_GR="Όνομα οχήματος: %1  Σιγουρευτείτε\nότι είναι ενεργοποιημένο το Bluetooth στη συσκευή\nσας και ότι ενεργοποιήθηκε η ορατότητα.", en_GB="Vehicle name: %1  Please check that\nBluetooth is activated on your device and\ndiscoverability is switched on.", es_ES="Nombre del vehículo: %1  Por favor,\nasegúrese de que el Bluetooth está activado en su\ndispositivo y de haber activado la visibilidad.", fi_FI="Auton nimi: %1  Varmista, että\nlaitteesi Bluetooth on kytketty päälle ja näkyvyys on\naktivoitu.", fr_FR="Nom du véhicule: %1  Veuillez vous\nassurer que la fonction Bluetooth est activée sur\nvotre périphérique et que ce dernier est visible.", hr_HR="Naziv vozila: %1  Provjerite je li\nuključen Bluetooth na vašem uređaju i je li aktivirana\nvidljivost.", hu_HU="Jármű neve: %1  Kérünk, ellenőrizd,\nhogy a Bluetooth be van-e kapcsolva a készülékeden,\nés a láthatóság aktiválásra került-e.", it_IT="Nome vettura: %1  Accertarsi che la\nfunzione Bluetooth del dispositivo sia accesa e che\nsia attivata la visibilità.", nl_NL="Naam voertuig: %1  Zorg ervoor dat\nBluetooth is ingeschakeld op je apparaat en de\nzichtbaarheid is geactiveerd.", no_NO="Bilens navn: %1  Forsikre deg om at\nBluetooth er slått på på enheten, og at den er synlig.", pl_PL="Nazwa pojazdu: %1  Proszę się\nupewnić, że funkcja Bluetooth w Twoim urządzeniu\njest włączona i została aktywowana jego\nwidoczność.", pt_PT="Nome do veículo: %1  Por favor,\ncertifica-te que o Bluetooth está ligado no teu\naparelho e que a visibilidade foi ativada.", ro_RO="Nume autovehicul: %1  Asiguraţi-vă\ncă Bluetooth este activat pe dispozitivul\ndumneavoastră şi că a fost activată vizibilitatea.", ru_RU="Имя автомобиля: %1  Пожалуйста,\nубедитесь, что функция Bluetooth в Вашем\nустройстве включена, а также активирована\nфункция видимости.", sk_SK="Názov vozidla: %1  Prosím, uistite sa,\nže Bluetooth na vašom zariadeníi je zapnutý a\nviditeľnosť bola aktivovaná.", sl_SI="Ime vozila: %1  Preverite, da je\nBluetooth na vaši napravi vključen in vidnost\naktivirana.", sr_RS="Naziv vozila: %1  Uverite se da je\nBluetooth na vašem uređaju uključen i vidljivost\naktivirana.", sv_SE="Fordonsnamn: %1  Se till att\nBluetooth har aktiverats på din enhet och att\nsynlighet har aktiverats.", tr_TR="Araç adı: %1  Lütfen cihazında\nBluetooth özelliğinin açık ve görünürlüğün aktif\nolduğundan emin ol.", uk_UA="Ім’я автомобіля: %1 \nПереконайтеся, що на пристрої ввімкнено\nBluetooth і пристрій зроблено видимим.")
connection_mgr__bluetooth__pairing__simple_compare__top_text = TextObject(bs_BA="Potvrdite PIN za Bluetooth vezu na mobilnom\ntelefonu: %1 Obratite pažnju na dodatne\nnapomene na mobilnom telefonu.", cs_CZ="Potvrďte prosím PIN pro připojení Bluetooth na\nmobilním telefonu: %1 Dodržujte další pokyny\nna mobilním telefonu.", da_DK="Bekræft pinkoden til Bluetooth-forbindelsen på\nmobiltelefonen: %1 Vær opmærksom på\nyderligere anvisninger på mobiltelefonen.", de_DE="Bitte bestätige die PIN für die Bluetooth-Verbindung\nauf dem Mobiltelefon: %1 Bitte beachte\nweitere Hinweise auf dem Mobiltelefon.", el_GR="Επιβεβαιώστε το PIN για τη σύνδεση Bluetooth στο\nκινητό τηλέφωνο: %1 Προσέξτε τυχόν\nπεραιτέρω υποδείξεις στο κινητό τηλέφωνο.", en_GB="Please confirm the PIN for the Bluetooth connection\non the mobile phone: %1 Please follow the\ninstructions on the mobile phone.", es_ES="Por favor, confirme el PIN para la conexión\nBluetooth en el teléfono móvil: %1 Siga las\nindicaciones que aparezcan en el teléfono móvil.", fi_FI="Vahvista PIN-koodi Bluetooth-yhteyttä varten\nmatkapuhelimesta: %1 Huomioi muut ohjeet\nmatkapuhelimen näytöllä.", fr_FR="Veuillez confirmer sur le téléphone portable le code\nPIN pour la connexion Bluetooth: %1 Veuillez\ntenir compte des indications sur le téléphone\nportable.", hr_HR="Potvrdite PIN za Bluetooth vezu na mobilnom\ntelefonu: %1 Uvažite daljnje napomene na\nmobilnom telefonu.", hu_HU="Kérünk, erősítsd meg a Bluetooth-kapcsolat\nPIN-kódját a mobiltelefonon: %1 Kérünk, vedd\nfigyelembe a további információkat a\nmobiltelefonon.", it_IT="Confermare il PIN per il collegamento Bluetooth sul\ntelefono cellulare: %1 Osservare le ulteriori\nistruzioni sul telefono cellulare.", nl_NL="Bevestig je pincode voor de Bluetoothverbinding op\nje mobiele telefoon: %1 Volg de verdere\naanwijzingen op je mobiele telefoon.", no_NO="Bekreft PIN-koden for Bluetooth-forbindelsen på\nmobiltelefonen: %1 Følg annen informasjon på\nmobiltelefonen.", pl_PL="Proszę potwierdzić kod PIN połączenia Bluetooth w\ntelefonie komórkowym: %1 Proszę stosować\nsię do dalszych wskazówek wyświetlanych w\ntelefonie komórkowym.", pt_PT="Por favor, confirma o PIN para a ligação Bluetooth\nno teu telemóvel: %1 Por favor, segue as\nrestantes instruções no teu telemóvel.", ro_RO="Confirmaţi codul PIN pentru conexiunea Bluetooth\npe telefonul mobil: %1 Respectaţi indicaţiile\nsuplimentare de pe telefonul mobil.", ru_RU="Пожалуйста, подтвердите PIN для соединения\nBluetooth на мобильном телефоне: %1\nОбратите внимание на дополнительные указания\nна мобильном телефоне.", sk_SK="Prosím, potvrďte kód PIN pre pripojenie Bluetooth\nna mobilnom telefóne: %1 Prosím, dbajte na\nďalšie pokyny v mobilnom telefóne.", sl_SI="Potrdite PIN-kodo za Bluetooth povezavo na\nmobilnem telefonu: %1 Upoštevajte nadaljnje\nnapotke na mobilnem telefonu.", sr_RS="Potvrdite PIN za povezivanje sa Bluetooth na\nmobilnom telefonu: %1 Obratite pažnju na\ndodatne napomene na mobilnom telefonu.", sv_SE="Bekräfta PIN-koden för Bluetoothanslutning på\nmobiltelefonen: %1 Observera ytterligare\nanvisningar på mobiltelefonen.", tr_TR="Lütfen cep telefonunda Bluetooth bağlantısı için\nPIN'i onayla: %1 Lütfen cep telefonundaki\ndiğer notları dikkate al.", uk_UA="Будь ласка, підтвердьте PIN-код для з'єднання\nBluetooth на мобільному телефоні: %1\nЗверніть увагу на додаткові вказівки на\nмобільному телефоні.")
connection_mgr__bluetooth__pairing__successful_connected__text = TextObject(bs_BA="Proces povezivanja je uspješno završen. Može\npotrajati nekoliko trenutaka do uspostavljanja veze. \nObratite pažnju na moguće napomene na uređaju.", cs_CZ="Proces párování byl úspěšně dokončen. Navázání\nspojení může trvat několik okamžiků.  Berte prosím\nna vědomí veškeré pokyny na zařízení.", da_DK="Parring blev afsluttet korrekt. Det kan tage et\nøjeblik, inden der oprettes forbindelse.  Vær\nopmærksom på mulige anvisninger på apparatet.", de_DE="Der Kopplungsprozess wurde erfolgreich\nabgeschlossen. Es kann einige Augenblicke dauern,\nbis die Verbindung hergestellt wird.  Bitte beachte\nmögliche Hinweise auf dem Gerät.", el_GR="Η διαδικασία σύζευξης ολοκληρώθηκε με επιτυχία.\nΜπορεί να χρειαστούν μερικές στιγμές, ώσπου να\nδημιουργηθεί η σύνδεση.  Λάβετε υπόψη σας\nενδεχόμενες υποδείξεις στη συσκευή.", en_GB="The device was paired successfully. It may take a few\nmoments for the connection to be established. \nPlease follow any instructions on the device.", es_ES="La vinculación ha finalizado correctamente. La\nconexión puede tardar unos instantes.  Siga las\nindicaciones que aparezcan en el dispositivo.", fi_FI="Kytkentäprosessi onnistui. Yhteyden\nmuodostaminen saattaa kestää hetken.  Huomioi\nmahdolliset ohjeet laitteen näytöllä.", fr_FR="La procédure de jumelage a été réalisée avec succès.\nL'établissement de la connexion peut prendre\nquelques instants.  Veuillez tenir compte des\npossibles indications sur le périphérique.", hr_HR="Proces povezivanja uspješno je završen. Može\npotrajati nekoliko trenutaka dok se ne uspostavi\nveza.  Uvažite eventualne napomene na uređaju.", hu_HU="A párosítási folyamat sikeresen befejeződött. A\nkapcsolat létrehozásához néhány pillanat szükséges.\n Vedd figyelembe a készüléken megjelenő esetleges\nfigyelmeztetéseket.", it_IT="Il processo di abbinamento è stato completato\ncorrettamente. La creazione del collegamento\npotrebbe richiedere qualche istante. Osservare le\neventuali istruzioni sul dispositivo.", nl_NL="Het koppelingsproces is afgesloten. Het kan eventjes\nduren voordat de verbinding tot stand is gebracht. \nHoud rekening met de aanwijzingen op je apparaat.", no_NO="Tilkoblingen er fullført. Det kan ta en liten stund før\nforbindelsen er opprettet.   Se eventuelle meldinger\npå enheten.", pl_PL="Proces parowania został pomyślnie zakończony.\nNawiązanie połączenia może potrwać kilka chwil. \nZwracaj uwagę na możliwe komunikaty w\nurządzeniu.", pt_PT="O emparelhamento foi concluído com sucesso. Pode\ndemorar um pouco até a ligação serestabelecida. \nPor favor, verifica possíveis indicações no aparelho.", ro_RO="Procesul de asociere s-a încheiat cu succes. Poate\ndura câteva momente, până la realizarea conexiunii. \nŢineţi cont de posibilele indicaţii de pe aparat.", ru_RU="Процесс сопряжения успешно завершен.\nУстановление соединения может занять несколько\nминут.  Следуйте инструкциям на устройстве.", sk_SK="Proces spojenia bol úspešne ukončený. Môže chvíľu\ntrvať, kým sa vytvorí spojenie.  Prosím, dbajte na\nvšetky upozornenia na zariadení.", sl_SI="Postopek seznanjanja je bil uspešno zaključen. Lahko\ntraja nekaj trenutkov, da se povezava vzpostavi. \nUpoštevajte morebitne napotke na vaši napravi.", sr_RS="Proces povezivanja je uspešno završen. Može da\npotraje nekoliko trenutaka do uspostavljanja veze. \nObratite pažnju na moguće napomene na uređaju.", sv_SE="Kopplingsprocessen lyckades. Det kan ta en stund\ninnan anslutningen är upprättad.  Observera\neventuell information på enheten.", tr_TR="Eşleştirme işlemi başarıyla tamamlandı. Bağlantı\nkurulana kadar birkaç dakika sürebilir.  Lütfen\ncihazdaki olası notları dikkate al.", uk_UA="Процес створення пари успішно завершено.\nВстановлення з'єднання може зайняти кілька\nхвилин.  Дотримуйтесь інструкцій на пристрої.")
