connection_mgr__ecall_manual_input_save_number_button = TextObject(bs_BA="Memorisati broj telefona", cs_CZ="Uložit tel. číslo", da_DK="Gem telefonnummer", de_DE="Telefonnummer speichern", el_GR="Αποθήκευση αριθμού τηλεφώνου", en_GB="Save phone number", es_ES="Memorizar número de teléfono", fi_FI="Tallenna puhelinnumero", fr_FR="Mémoriser le numéro de téléphone", hr_HR="Pohraniti telefonski broj", hu_HU="Telefonszám mentése", it_IT="Memorizza numero telefonico", nl_NL="Telefoonnummer opslaan", no_NO="Lagre telefonnummer", pl_PL="Zapisz numer telefonu", pt_PT="Guardar número de telefone", ro_RO="Memorare număr de telefon", ru_RU="Сохранить номер телефона", sk_SK="Uložiť telefónne číslo", sl_SI="Shranjevanje telefonske številke", sr_RS="Memorisanje broja telefona", sv_SE="Spara telefonnummer", tr_TR="Telefon numarasını kaydet", uk_UA="Зберегти номер телефону")
connection_mgr__ecall_manual_input_text = TextObject(bs_BA="Ovdje možete definisati broj telefona, uključujući pozivni broj zemlje za trenutno povezani uređaj. On će u slučaju hitnog poziva biti\nproslijeđen centralu za hitne pozive.", cs_CZ="Zde můžete uložit tel. číslo včetně předvolby země aktuálně připojeného zařízení. To bude v případě nouzového volání předáno centru\ntísňového volání.", da_DK="Her kan du gemme et telefonnummer inklusive landekode til det aktuelt forbundne apparat. Dette overføres til nødopkaldscentralen i\ntilfælde af et nødopkald.", de_DE="Hier kannst du eine Telefonnummer inklusive Ländervorwahl für das aktuell verbundene Gerät hinterlegen. Diese wird im Falle eines Notrufs\nan die Notrufzentrale übertragen.", el_GR="Εδώ μπορείτε να δηλώσετε έναν αριθμό τηλεφώνου, συμπεριλαμβανομένου του κωδικού κλήσης χώρας για την εκάστοτε συνδεδεμένη συσκευή.\nΑυτός, σε περίπτωση κλήσης ανάγκης, μεταβιβάζεται στο κέντρο κλήσεων ανάγκης.", en_GB="You can save your telephone number and country code for the currently connected device here. This information will be transmitted to the\nemergency call centre in the event of an emergency call.", es_ES="Aquí puede memorizar un número de teléfono (incluido el prefijo del país) para el dispositivo conectado actualmente. Este número se\ntransmitirá a la central de emergencias en caso de producirse una llamada de emergencia.", fi_FI="Tässä voit tallentaa yhdistetylle laitteelle maatunnuksen sisältävän puhelinnumeron. Hätäpuhelun yhteydessä se välitetään hätäkeskukselle.", fr_FR="Ici, vous pouvez définir un numéro de téléphone comprenant l'indicatif du pays pour le périphérique connecté actuellement. En cas d'appel\nd'urgence, celui-ci est transmis à la centrale du service d'appel d'urgence.", hr_HR="Tu možete pohraniti telefonski broj, uključujući i pozivni broj zemlje, za trenutačno spojeni uređaj. On će se u slučaju poziva u nuždi prenijeti\ncentrali za pozive u nuždi.", hu_HU="Itt menthetsz egy telefonszámot, beleértve az aktuálisan csatlakoztatott eszköz országhívószámát. Segélyhívás esetén ezt kapja meg a\nsegélyhívó központ.", it_IT="Qui è possibile memorizzare un numero telefonico comprensivo del prefisso internazionale per il dispositivo attualmente collegato, che verrà\ntrasmesso alla centrale per le chiamate d'emergenza in caso di chiamata d'emergenza.", nl_NL="Hier kun je een telefoonnummer invoeren, inclusief de landcode voor het momenteel verbonden apparaat. Dit wordt bij een noodoproep\ndoorgegeven aan de alarmcentrale.", no_NO="Her kan du lagre et telefonnummer med landskode for enheten som har forbindelse. Nummeret overføres til nødanropssentralen under et\nnødanrop.", pl_PL="W tym miejscu możesz zapisać numer telefonu wraz z numerem kierunkowym kraju dla aktualnie podłączonego urządzenia. Zostanie on\nprzesłany do centrali w przypadku połączenia alarmowego.", pt_PT="Aqui podes introduzir um número de telefone incluindo o indicativo do país para o aparelho atualmente ligado. No caso de uma chamada de\nemergência este é transferido para a central de chamadas de emergência.", ro_RO="Aici se poate memora un număr de telefon, inclusiv prefixul ţării, pentru dispozitivul conectat actual. Acesta este transmis centralei de apel\nde urgenţă, în cazul unui apel de urgenţă.", ru_RU="Здесь можно ввести номер телефона, включая код страны, для подключенного в данный момент устройства. Этот номер будет передан\nв центр экстренных вызовов в случае экстренного вызова.", sk_SK="Tu môžete zadať telefónne číslo vrátane predvoľby krajiny aktuálne pripojeného zariadenia. Toto sa v prípade núdzového volania prenesie do\ncentra núdzového volania.", sl_SI="Tukaj lahko shranite telefonsko številko, vključno s klicno številko države, za trenutno povezano napravo. Sistem bo številko v primeru klica v\nsili posredoval centrali za klic v sili.", sr_RS="Ovde možete utvrditi broj telefona, uključujući pozivni broj zemlje za trenutno povezani uređaj. On će biti prosleđen u centralu za hitne\npozive u slučaju poziva u nevolji.", sv_SE="Här kan du lägga till ett telefonnummer samt ett förvalt land för den anslutna enheten. Vid nödsamtal kommer detta att förmedlas till\nlarmcentralen.", tr_TR="Buraya, halihazırda bağlı olan cihaz için ülke kodunu da içeren bir telefon numarası kaydedebilirsin. Bir acil çağrı durumunda bu numara acil\nçağrı merkezine iletilir.", uk_UA="Тут ви можете ввести номер телефону з кодом країни для підключеного пристрою. У разі екстреного виклику цей номер буде передано\nдо центру обробки екстрених викликів.")
connection_mgr__ecall_manual_input_title = TextObject(bs_BA="Broj telefona u slučaju hitnog poziva", cs_CZ="Tel. číslo v případě nouzového volání", da_DK="Telefonnummer i tilfælde af et nødopkald", de_DE="Telefonnummer im Falle eines Notrufs", el_GR="Αριθμός τηλεφώνου για την περίπτωση κλήσης ανάγκης", en_GB="Phone number for an emergency call", es_ES="Número de teléfono en caso de llamada de emergencia", fi_FI="Puhelinnumero hätäpuheluita varten", fr_FR="Numéro de téléphone en cas d'appel d'urgence", hr_HR="Telefonski broj u slučaju poziva u nuždi", hu_HU="Telefonszám segélyhívás esetén", it_IT="Numero telefonico in caso di chiamata d'emergenza", nl_NL="Telefoonnummer in geval van een noodoproep", no_NO="Telefonnummer i tilfelle nødanrop", pl_PL="Numer telefonu w przypadku połączenia alarmowego", pt_PT="Número de telefone em caso de uma chamada de emergência", ro_RO="Număr de telefon în cazul unui apel de urgenţă", ru_RU="Номер телефона на случай экстренного вызова", sk_SK="Telefónne číslo v prípade núdzového volania", sl_SI="Telefonska številka v primeru klica v sili", sr_RS="Broj telefona u slučaju poziva u nevolji", sv_SE="Telefonnummer i händelse av nödsamtal", tr_TR="Bir acil çağrı durumunda telefon numarası", uk_UA="Номер телефону на випадок екстреного виклику")
connection_mgr__error_or_hint_texts___change_vehicle_name__user_name_field__too_short_error = TextObject(bs_BA="Unesite najmanje 4 znaka.", cs_CZ="Zadejte nejméně 4 znaky.", da_DK="Angiv mindst 4 tegn.", de_DE="Bitte gib mindestens 4 Zeichen ein.", el_GR="Καταχωρίστε τουλάχιστον 4 χαρακτήρες.", en_GB="Please enter at least 4 characters.", es_ES="Por favor, introduzca por lo menos 4 caracteres.", fi_FI="Syötä vähintään 4 merkkiä.", fr_FR="Veuillez entrer au moins 4 caractères.", hr_HR="Unesite najmanje 4 znaka.", hu_HU="Kérünk, adj meg legalább 4 karaktert.", it_IT="Immettere almeno 4 caratteri.", nl_NL="Voer minimaal 4 tekens in.", no_NO="Legg inn minst 4 tegn.", pl_PL="Proszę wprowadzić ci najmniej 4 znaki.", pt_PT="Por favor, introduz pelo menos 4 caracteres.", ro_RO="Introduceţi cel puţin 4 caractere.", ru_RU="Пожалуйста, введите не менее 4 символов.", sk_SK="Prosím, zadajte najmenej 4 znaky.", sl_SI="Vnesite vsaj 4 znake.", sr_RS="Unesite najmanje 4 znaka.", sv_SE="Ange minst 4 tecken.", tr_TR="Lütfen en az 4 karakter gir.", uk_UA="Введіть щонайменше 4 символи.")
