dial_pad_disclaimer_text = TextObject(bs_BA="Možete unijeti broj telefona ili pretraživati kontakte.", cs_CZ="Můžete zadat telefonní číslo nebo vyhledat kontakt.", da_DK="Du kan indtaste et telefonnummer eller søge efter en kontakt.", de_DE="Du kannst eine Telefonnummer eingeben oder nach einem Kontakt\nsuchen.", el_GR="Μπορείτε να καταχωρίσετε έναν αριθμό τηλεφώνου ή να αναζητήσετε\nμια επαφή.", en_GB="You can enter a telephone number or search for a contact.", es_ES="Puede introducir un número de teléfono o buscar un contacto.", fi_FI="Voit syöttää puhelinnumeron tai etsiä yhteystietoa.", fr_FR="Vous pouvez entrer un numéro de téléphone ou rechercher un\ncontact.", hr_HR="Možete unijeti telefonski broj ili tražiti kontakt.", hu_HU="Megadhatsz egy telefonszámot, vagy rákereshetsz egy névjegyre.", it_IT="È possibile immettere un numero telefonico o cercare un contatto.", nl_NL="Je kunt een telefoonnummer invoeren of naar een contact zoeken.", no_NO="Du kan legge inn et telefonnummer eller søke etter en kontakt.", pl_PL="Możesz wpisać numer telefonu lub wyszukać kontakt.", pt_PT="Podes introduzir um número de telefone ou procurar um contacto.", ro_RO="Puteţi introduce un număr de telefon sau puteţi căuta un contact.", ru_RU="Вы можете ввести номер телефона или выполнить поиск\nконтакта.", sk_SK="Môžete zadať telefónne číslo alebo vyhľadať kontakt.", sl_SI="Lahko vnesete telefonsko številko ali poiščete stik.", sr_RS="Možete da unesete broj telefona ili da pretražujete kontakte.", sv_SE="Du kan ange ett telefonnummer eller söka efter en kontakt.", tr_TR="Bir telefon numarası girebilir veya bir kişiyi arayabilirsin.", uk_UA="Ви можете ввести номер телефону або здійснити пошук контакту.")
