msg__send_message__template_list__list_item__template_2_text = TextObject(bs_BA="U zastoju sam i zakasniću.", cs_CZ="Jsem v dopravní zácpě a budu mít zpoždění.", da_DK="Jeg holder i kø og bliver forsinket.", de_DE="Ich stehe im Stau und verspäte mich.", el_GR="Είμαι σε μποτιλιάρισμα και θα αργήσω.", en_GB="I'm stuck in traffic and will be late.", es_ES="Estoy en una retención y llego tarde.", fi_FI="Seison ruuhkassa ja myöhästyn.", fr_FR="Je suis bloqué dans un embouteillage, j'aurai du retard.", hr_HR="Zapeo sam u zastoju i zakasnit ću.", hu_HU="Elakadtam a forgalomban, és késésben vagyok.", it_IT="Sono in coda e arriverò in ritardo.", nl_NL="Ik sta in de file en kom iets later aan.", no_NO="Jeg står i kø og blir forsinket.", pl_PL="Stoję w korku, spóźnię się.", pt_PT="Estou no trânsito e vou atrasar-me.", ro_RO="Sunt blocat(ă) în trafic şi voi întârzia.", ru_RU="Я стою в пробке и опаздываю.", sk_SK="Stojím v zápche a budem meškať.", sl_SI="Sem v zastoju in bom zamudil(a).", sr_RS="Nalazim se u zastoju i zakasniću.", sv_SE="Jag sitter i kö och blir försenad.", tr_TR="Trafikte duruyorum ve gecikiyorum.", uk_UA="Я стою в пробці і запізнююся.")
msg__send_message__template_list__list_item__template_3_text = TextObject(bs_BA="Trenutno sam u vozilu i javiću se kasnije.", cs_CZ="Jsem právě v autě a ozvu se později.", da_DK="Jeg sidder lige i bilen. Jeg kontakter dig på et senere tidspunkt.", de_DE="Ich bin gerade im Auto und melde mich später.", el_GR="Αυτή τη στιγμή είμαι στο αυτοκίνητο και θα επικοινωνήσω αργότερα.", en_GB="I'm in the car and will contact you later.", es_ES="Estoy en el coche, luego contesto.", fi_FI="Olen nyt autossa ja palaan asiaan myöhemmin.", fr_FR="Je suis en voiture, je vous rappelle plus tard.", hr_HR="Upravo sam u autu i javit ću se poslije.", hu_HU="Éppen vezetek, később jelentkezem.", it_IT="Sono in auto e chiamerò più tardi.", nl_NL="Ik ben nog in de auto en kom iets later.", no_NO="Jeg er i bilen nå og tar kontakt senere.", pl_PL="Jestem teraz w samochodzie, odezwę się później.", pt_PT="Agora estou no carro e ligo mais tarde.", ro_RO="Sunt în maşină şi o sa vă contactez mai târziu.", ru_RU="Я сейчас в машине, позвоню позже.", sk_SK="Práve som v aute a ozvem sa neskôr.", sl_SI="Vozim, pokličem pozneje.", sr_RS="Trenutno sam u automobilu i javiću se kasnije.", sv_SE="Jag är i bilen och kontaktar dig senare.", tr_TR="Şu anda arabadayım ve daha sonra arayacağım.", uk_UA="Я зараз у машині, зателефоную пізніше.")
