phone_not_attached__carplay_but_no_hfp_pid__text = TextObject(bs_BA="%1 je povezan s Apple CarPlay i može se koristiti samo na MMI. Želite li povezati\njoš jedan pametni telefon?", cs_CZ="%1 je připojeno k Apple CarPlay a lze jej použít pouze na MMI. Chcete připojit\ndalší smartphone?", da_DK="%1 er forbundet med Apple CarPlay og kan kun anvendes i MMI. Vil du forbinde\nendnu en smartphone?", de_DE="%1 ist mit Apple CarPlay verbunden und kann nur auf dem MMI genutzt werden.\nMöchtest du ein weiteres Smartphone verbinden?", el_GR="Το %1 είναι συνδεδεμένο με το Apple CarPlay και μπορεί να χρησιμοποιηθεί μόνο\nστο MMI. Θέλετε να συνδέσετε ένα ακόμη smartphone;", en_GB="%1 is connected via Apple CarPlay and can only be operated using the MMI. Do\nyou want to connect an additional smartphone?", es_ES="%1 está conectado con Apple CarPlay y solo se puede utilizar en el MMI. ¿Desea\nconectar otro smartphone?", fi_FI="%1 on yhdistetty Apple CarPlayhin ja sitä voi käyttää vain MMI:n kautta.\nHaluatko yhdistää toisen älypuhelimen?", fr_FR="%1 est connecté à Apple CarPlay et peut être utilisé uniquement via le MMI.\nSouhaitez-vous connecter un smartphone supplémentaire?", hr_HR="%1 je spojen s Apple CarPlayjem i može se koristiti samo u MMI­ju. Želite li spojiti\njoš jedan smartphone?", hu_HU="%1 csatlakozik az Apple CarPlay-hez, és csak az MMI-n használható. Szeretnél\ncsatlakoztatni egy másik okostelefont?", it_IT="%1 è collegato ad Apple CarPlay e può essere utilizzato solo sull'MMI. Collegare\nun altro smartphone?", nl_NL="%1 is verbonden met Apple CarPlay en kan alleen op de MMI worden gebruikt.\nWil je een andere smartphone aansluiten?", no_NO="%1 har forbindelse med Apple CarPlay og kan bare brukes på MMI. Vil du\nopprette forbindelse med en smarttelefon til?", pl_PL="%1 jest połączony z Apple CarPlay i może być używany tylko w MMI. Czy chcesz\npodłączyć inny smartfon?", pt_PT="%1 está ligado a Apple CarPlay e só pode ser usado no MMI. Queres ligar outro\nsmartphone?", ro_RO="%1 este conectat cu Apple CarPlay şi poate fi utilizat numai pe MMI. Doriţi să\nconectaţi încă un smartphone?", ru_RU="%1 подключен к Apple CarPlay и может использоваться только на MMI. Хотите\nподключить другой смартфон?", sk_SK="%1 je pripojený k Apple CarPlay a je možné ho použiť iba v systéme MMI. Chcete\npripojiť ďalší smartfón?", sl_SI="Naprava %1 je povezana z Apple CarPlay in jo je mogoče uporabljati samo v\nsistemu MMI. Ali želite povezati dodaten pametni telefon?", sr_RS="%1 je povezan sa Apple CarPlay i može da se koristi samo na MMI. Da li želite da\npovežete još jedan pametni telefon?", sv_SE="%1 är ansluten till Apple CarPlay och kan endast användas på MMI. Vill du\nansluta en smartphone till?", tr_TR="%1 Apple CarPlay ile bağlı ve yalnızca MMI'da kullanılabilir. Başka bir akıllı\ntelefon bağlamak istiyor musun?", uk_UA="%1 підключено до Apple CarPlay і його можна використовувати лише на MMI.\nХочете підключити інший смартфон?")
phone_not_attached__connect_phone__button_text = TextObject(bs_BA="Povežite mobilni telefon", cs_CZ="Připojte mobilní telefon", da_DK="Forbind mobiltelefon.", de_DE="Bitte Mobiltelefon verbinden", el_GR="Συνδέστε ένα κινητό τηλέφωνο", en_GB="Please connect mobile phone", es_ES="Por favor, conecte el teléfono móvil", fi_FI="Yhdistä matkapuhelin", fr_FR="Veuillez connecter un téléphone portable", hr_HR="Spojiti mobilni telefon", hu_HU="Csatlakoztasd a mobiltelefont", it_IT="Collegare il telefono cellulare", nl_NL="Maak verbinding met uw mobiele telefoon", no_NO="Opprett forbindelse med mobiltelefon", pl_PL="Proszę podłączyć telefon komórkowy", pt_PT="Por favor, ligue um telemóvel", ro_RO="Conectaţi telefonul mobil", ru_RU="Подключите мобильный телефон", sk_SK="Prosím, pripojte mobilný telefón", sl_SI="Povežite mobilni telefon", sr_RS="Povežite mobilni telefon", sv_SE="Anslut mobiltelefonen", tr_TR="Lütfen mobil telefonu bağlayın", uk_UA="Підключіть мобільний телефон")
phone_not_attached__connecting_new_phone_not_allowed_while_driving = TextObject(bs_BA="Povežite pametni telefon. Tokom vožnje je moguće samo povezivanje poznatih uređaja.", cs_CZ="Připojte smartphone. Během jízdy lze připojit pouze známá zařízení.", da_DK="Opret forbindelse til en smartphone. Under kørsel er det kun kendte apparater, der kan oprettes forbindelse\ntil.", de_DE="Bitte verbinde ein Smartphone. Während der Fahrt können nur bekannte Geräte verbunden werden.", el_GR="Συνδέστε ένα smartphone. Κατά τη διαδρομή μπορούν να συνδεθούν μόνο γνωστές συσκευές.", en_GB="Please connect a smartphone. Only known devices can be connected while driving.", es_ES="Por favor, conecte un smartphone. Durante la marcha solo se pueden conectar dispositivos conocidos.", fi_FI="Yhdistä älypuhelin. Ajon aikana voidaan yhdistää vain tunnettuja laitteita.", fr_FR="Veuillez connecter un smartphone. Seuls les périphériques connus peuvent être connectés pendant la\nconduite.", hr_HR="Spojite smartphone. Tijekom vožnje moguće je spojiti samo poznate uređaje.", hu_HU="Csatlakoztass egy okostelefont. Vezetés közben csak ismert eszközök csatlakoztathatók.", it_IT="Collegare uno smartphone. Durante la marcia è possibile collegare solo i dispositivi conosciuti.", nl_NL="Verbind een smartphone. Tijdens de rit kunnen alleen bekende apparaten worden verbonden.", no_NO="Opprett forbindelse med en smarttelefon. Det kan bare opprettes forbindelse med kjente enheter under\nkjøring.", pl_PL="Podłącz smartfon. Podczas jazdy można podłączać tylko znane urządzenia.", pt_PT="Por favor, liga um smartphone. Durante a viagem só podem ser ligados aparelhos conhecidos.", ro_RO="Conectaţi un smartphone. În timpul deplasării pot fi conectate numai dispozitive cunoscute.", ru_RU="Подключите смартфон. Во время поездки можно подключать только известные устройства.", sk_SK="Prosím, pripojte smartfón. Počas jazdy je možné pripojiť len známe zariadenia.", sl_SI="Povežite pametni telefon. Med vožnjo je mogoče povezati samo znane naprave.", sr_RS="Molimo da povežete pametni telefon. Tokom vožnje moguće je samo povezivanje poznatih uređaja.", sv_SE="Anslut en smartphone. Under körningen kan endast bekanta enheter anslutas.", tr_TR="Lütfen bir akıllı telefon bağla. Sürüş sırasında sadece bilinen cihazlar bağlanabilir.", uk_UA="Підключіть смартфон. Під час поїздки можна підключати тільки відомі пристрої.")
phone_not_attached__empty_list__text = TextObject(bs_BA="Nema povezanog telefona sa %1.", cs_CZ="Není připojen žádný telefon k %1.", da_DK="Ingen telefon forbundet med %1.", de_DE="Es ist kein Telefon verbunden mit %1.", el_GR="Δεν είναι συνδεδεμένο κανένα τηλέφωνο με το %1.", en_GB="No telephone is connected to %1.", es_ES="No hay ningún teléfono conectado con %1.", fi_FI="Puhelinta ei ole yhdistetty järjestelmään %1.", fr_FR="Aucun téléphone n'est connecté à %1.", hr_HR="Nema spojenog telefona sa %1.", hu_HU="Nincs összekapcsolva telefon a következővel: %1.", it_IT="Nessun telefono collegato con %1.", nl_NL="Er is geen telefoon verbonden met %1.", no_NO="Ingen telefon har forbindelse med %1.", pl_PL="Brak telefonu połączonego z %1.", pt_PT="Não existem telefones ligados ao %1.", ro_RO="Nu este conectat niciun telefon cu %1.", ru_RU="Телефон не подключен к %1.", sk_SK="K %1 nie je pripojený žiadny telefón.", sl_SI="S sistemom %1 ni povezan noben telefon.", sr_RS="Nijedan telefon nije povezan sa %1.", sv_SE="Ingen telefon är ansluten till %1.", tr_TR="Hiçbir telefon %1 ile bağlı değil.", uk_UA="Телефон не підключено до %1.")
phone_not_attached__korea_sos__button_text = TextObject(bs_BA="Emergency Call", cs_CZ="Emergency Call", da_DK="Nødopkald", de_DE="Emergency Call", el_GR="Emergency Call", en_GB="Emergency call", es_ES="Emergency Call", fi_FI="Emergency Call", fr_FR="Appel d'urgence", hr_HR="Poziv u nuždi", hu_HU="Emergency Call", it_IT="Emergency Call", nl_NL="Noodoproep", no_NO="Emergency Call", pl_PL="Połączenie alarmowe", pt_PT="Chamada de emergência", ro_RO="Emergency Call", ru_RU="Emergency Call", sk_SK="Emergency Call", sl_SI="Emergency Call", sr_RS="Emergency Call", sv_SE="Emergency Call", tr_TR="Emergency Call", uk_UA="Emergency Call")
