texttool_globals_dialog_message___connection_mgr__activation_dialog_bluetooth__text = TextObject(bs_BA="Bluetooth je deaktiviran. Aktivirajte Bluetooth da biste mogli koristiti funkciju.", cs_CZ="Bluetooth je deaktivován. Aktivujte prosím Bluetooth, abyste mohli funkci používat.", da_DK="Bluetooth deaktiveret. Aktiver Bluetooth for at kunne anvende funktionen.", de_DE="Bluetooth ist deaktiviert. Bitte aktiviere Bluetooth, um die Funktion nutzen zu\nkönnen.", el_GR="Το Bluetooth είναι απενεργοποιημένο. Ενεργοποιήστε το Bluetooth, για να\nμπορέσετε να χρησιμοποιήσετε τη λειτουργία.", en_GB="Bluetooth is deactivated. Please activate Bluetooth to use the function.", es_ES="El Bluetooth está desactivado. Por favor, active el Bluetooth para poder utilizar la\nfunción.", fi_FI="Bluetooth on deaktivoitu. Aktivoi Bluetooth käyttääksesi toimintoa.", fr_FR="Le Bluetooth est désactivé. Veuillez activer le Bluetooth pour pouvoir utiliser la\nfonction.", hr_HR="Bluetooth je deaktiviran. Aktivirajte Bluetooth kako biste mogli koristiti funkciju.", hu_HU="Bluetooth deaktiválva. A funkció használatához aktiváld a Bluetooth-t.", it_IT="Bluetooth disattivato. Attivare il Bluetooth per poter utilizzare la funzione.", nl_NL="Bluetooth is gedeactiveerd. Activeer Bluetooth om de functie te kunnen gebruiken.", no_NO="Bluetooth er deaktivert. Du må aktivere Bluetooth for å bruke funksjonen.", pl_PL="Bluetooth jest wyłączone. Aby korzystać z tej funkcji, proszę włączyć Bluetooth.", pt_PT="Bluetooth está desativado. Por favor, ativa o Bluetoth para poderes utilizar a\nfunção.", ro_RO="Bluetooth este dezactivat. Activaţi Bluetooth, pentru a putea utiliza funcţia.", ru_RU="Bluetooth отключен. Включите Bluetooth, чтобы использовать эту функцию.", sk_SK="Bluetooth je deaktivovaný. Prosím, ak chcete funkciu používať, aktivujte Bluetooth.", sl_SI="Bluetooth je deaktiviran. Za uporabo funkcije aktivirajte Bluetooth.", sr_RS="Bluetooth je deaktiviran. Aktivirajte Bluetooth da biste mogli koristiti funkciju.", sv_SE="Bluetooth är avaktiverat. Aktivera Bluetooth för att kunna använda funktionen.", tr_TR="Bluetooth devre dışı bırakıldı. Fonksiyonu kullanabilmek için, lütfen Bluetooth'u\netkinleştir.", uk_UA="Bluetooth вимкнено. Увімкніть Bluetooth, щоб використовувати цю функцію.")
texttool_globals_dialog_message___connection_mgr__activation_dialog_bluetooth_android_auto__text = TextObject(bs_BA="Bluetooth je deaktiviran. Aktivirajte Bluetooth da biste u potpunosti mogli koristiti\nAndroid Auto.", cs_CZ="Bluetooth je deaktivován. Aktivujte prosím Bluetooth, abyste mohli úplně používat\nAndroid Auto.", da_DK="Bluetooth deaktiveret. Aktiver Bluetooth for at kunne anvende Android Auto i fuldt\nomfang.", de_DE="Bluetooth ist deaktiviert. Bitte aktiviere Bluetooth, um Android Auto vollständig\nnutzen zu können.", el_GR="Το Bluetooth είναι απενεργοποιημένο. Ενεργοποιήστε το Bluetooth, για να\nμπορέσετε να χρησιμοποιήσετε πλήρως το Android Auto.", en_GB="Bluetooth is deactivated. Please activate Bluetooth to use Android Auto fully.", es_ES="El Bluetooth está desactivado. Por favor, active el Bluetooth para poder utilizar\ntodas las funciones de Android Auto.", fi_FI="Bluetooth on deaktivoitu. Aktivoi Bluetooth, jotta Android Auto on täysin\nkäytettävissä.", fr_FR="Le Bluetooth est désactivé. Veuillez activer le Bluetooth pour pouvoir utiliser\nl'intégralité d'Android Auto.", hr_HR="Bluetooth je deaktiviran. Aktivirajte Bluetooth kako biste mogli u potpunosti\nkoristiti Android Auto.", hu_HU="Bluetooth deaktiválva. Az Android Auto teljes körű használatához aktiváld a\nBluetooth-t.", it_IT="Bluetooth disattivato. Attivare il Bluetooth per poter utilizzare Android Auto in\nmodo completo.", nl_NL="Bluetooth is gedeactiveerd. Activeer Bluetooth om Android Auto volledig te kunnen\ngebruiken.", no_NO="Bluetooth er deaktivert. Du må aktivere Bluetooth for å bruke Android Auto i fullt\nomfang.", pl_PL="Bluetooth jest wyłączone. Aby w pełni korzystać z Android Auto, proszę włączyć\nBluetooth.", pt_PT="Bluetooth está desativado. Por favor, ativa o Bluetooth para poderes utilizar\nplenamente Android Auto.", ro_RO="Bluetooth este dezactivat. Activaţi Bluetooth, pentru a putea utiliza integral\nAndroid Auto.", ru_RU="Bluetooth отключен. Включите Bluetooth, чтобы использовать Android Auto в\nполном объеме.", sk_SK="Bluetooth je deaktivovaný. Prosím, ak chcete Android Auto plnohodnotne používať,\naktivujte Bluetooth.", sl_SI="Bluetooth je deaktiviran. Aktivirajte Bluetooth, da boste Android Auto lahko\nuporabljali v celoti.", sr_RS="Bluetooth je deaktiviran. Aktivirajte Bluetooth da biste u celosti mogli koristiti\nAndroid Auto.", sv_SE="Bluetooth är avaktiverat. Aktivera Bluetooth för att kunna använda Android Auto\nhelt.", tr_TR="Bluetooth devre dışı bırakıldı. Android Auto'yu tam olarak kullanabilmek için, lütfen\nBluetooth'u etkinleştir.", uk_UA="Bluetooth вимкнено. Увімкніть Bluetooth, щоб використовувати Android Auto у\nповному обсязі.")
texttool_globals_dialog_message___connection_mgr__activation_dialog_bluetooth_car_play__text = TextObject(bs_BA="Bluetooth je deaktiviran. Aktivirajte Bluetooth da biste mogli koristiti Apple\nCarPlay.", cs_CZ="Bluetooth je deaktivován. Aktivujte prosím Bluetooth, abyste mohli používat Apple\nCarPlay.", da_DK="Bluetooth deaktiveret. Aktiver Bluetooth for at kunne anvende Apple CarPlay i fuldt\nomfang.", de_DE="Bluetooth ist deaktiviert. Bitte aktiviere Bluetooth, um Apple CarPlay nutzen zu\nkönnen.", el_GR="Το Bluetooth είναι απενεργοποιημένο. Ενεργοποιήστε το Bluetooth, για να\nμπορέσετε να χρησιμοποιήσετε το Apple CarPlay.", en_GB="Bluetooth is deactivated. Please activate Bluetooth to use Apple CarPlay.", es_ES="El Bluetooth está desactivado. Por favor, active el Bluetooth para poder utilizar\nApple CarPlay.", fi_FI="Bluetooth on deaktivoitu. Aktivoi Bluetooth käyttääksesi Apple CarPlay -toimintoa.", fr_FR="Le Bluetooth est désactivé. Veuillez activer le Bluetooth pour pouvoir utiliser Apple\nCarPlay.", hr_HR="Bluetooth je deaktiviran. Aktivirajte Bluetooth kako biste mogli koristiti Apple\nCarPlay.", hu_HU="Bluetooth deaktiválva. Az Apple CarPlay használatához aktiváld a Bluetooth-t.", it_IT="Bluetooth disattivato. Attivare il Bluetooth per poter utilizzare Apple CarPlay.", nl_NL="Bluetooth is gedeactiveerd. Activeer Bluetooth om Apple CarPlay te kunnen\ngebruiken.", no_NO="Bluetooth er deaktivert. Du må aktivere Bluetooth for å bruke Apple CarPlay.", pl_PL="Bluetooth jest wyłączone. Aby korzystać z Apple CarPlay, proszę włączyć Bluetooth.", pt_PT="Bluetooth está desativado. Por favor, ativa o Bluetooth para poderes utilizar Apple\nCarPlay.", ro_RO="Bluetooth este dezactivat. Activaţi Bluetooth, pentru a putea utiliza Apple CarPlay.", ru_RU="Bluetooth отключен. Включите Bluetooth, чтобы использовать Apple CarPlay.", sk_SK="Bluetooth je deaktivovaný. Prosím, ak chcete Apple CarPlay plnohodnotne používať,\naktivujte Bluetooth.", sl_SI="Bluetooth je deaktiviran. Za uporabo Apple CarPlay aktivirajte Bluetooth.", sr_RS="Bluetooth je deaktiviran. Aktivirajte Bluetooth da biste mogli koristiti Apple\nCarPlay.", sv_SE="Bluetooth är avaktiverat. Aktivera Bluetooth för att kunna använda Apple CarPlay\nhelt.", tr_TR="Bluetooth devre dışı bırakıldı. Apple CarPlay'i kullanabilmek için, lütfen Bluetooth'u\netkinleştir.", uk_UA="Bluetooth вимкнено. Увімкніть Bluetooth, щоб використовувати Apple CarPlay.")
