texttool_globals_toast___connection_mgr__ecall_number_successful_saved__text = TextObject(bs_BA="Vaš unos je uspješno sačuvan.", cs_CZ="Vaše zadání bylo úspěšně uloženo.", da_DK="Din angivelse blev gemt korrekt.", de_DE="Deine Eingabe wurde erfolgreich gespeichert.", el_GR="Η καταχώρισή σας αποθηκεύτηκε με επιτυχία.", en_GB="Your entry was saved successfully.", es_ES="Los datos introducidos se han memorizado correctamente.", fi_FI="Syöttämiesi tietojen tallennus onnistui.", fr_FR="Votre entrée a été mémorisée avec succès.", hr_HR="Vaš je unos uspješno pohranjen.", hu_HU="Bejegyzésed sikeresen elmentve.", it_IT="I dati immessi sono stati memorizzati correttamente.", nl_NL="Je invoer is opgeslagen.", no_NO="Opplysningene du la inn, ble lagret.", pl_PL="Twój wpis został pomyślnie zapisany.", pt_PT="Esta introdução foi guardada com sucesso.", ro_RO="Datele introduse au fost memorate cu succes.", ru_RU="Ваша запись успешно сохранена.", sk_SK="Vaše zadanie sa úspešne uložilo.", sl_SI="Vaš vnos je bil uspešno shranjen.", sr_RS="Vaš unos je uspešno sačuvan.", sv_SE="Inmatningen har sparats.", tr_TR="Girişin başarıyla kaydedildi.", uk_UA="Ваш запис успішно збережено.")
