texttool_globals_toast___disabled_reason__connectivity_out_of_region__text = TextObject(bs_BA="Funkcija nije raspoloživa u ovoj državi", cs_CZ="Funkce je v této zemi nedostupná", da_DK="Funktion ikke tilgængelig i dette land", de_DE="Funktion in diesem Land nicht verfügbar", el_GR="Η λειτουργία δεν είναι διαθέσιμη σε αυτή τη χώρα", en_GB="Function unavailable in this country", es_ES="Función no disponible en este país", fi_FI="Toiminto ei käytettävissä tässä maassa", fr_FR="Fonction non disponible dans ce pays", hr_HR="Funkcija nije raspoloživa u ovoj zemlji", hu_HU="A funkció ebben az országban nem áll rendelkezésre", it_IT="Funzione non disponibile in questo paese", nl_NL="Functie in dit land niet beschikbaar", no_NO="Funksjonen er ikke tilgjengelig i dette landet", pl_PL="Funkcja w tym kraju nie jest dostępna", pt_PT="Função não está disponível neste país", ro_RO="Funcţie indisponibilă în această ţară", ru_RU="Функция в этой стране недоступна", sk_SK="Funkcia v tejto krajine nie je k dispozícií", sl_SI="Funkcija v tej državi ni na voljo", sr_RS="Funkcija u ovoj zemlji nije raspoloživa", sv_SE="Funktionen ej tillgänglig i detta land", tr_TR="Fonksiyon bu ülkede mevcut değil", uk_UA="У цій країні функція недоступна")
texttool_globals_toast___disabled_reason__connectivity_time_expired__text = TextObject(bs_BA="Vaš paket podataka je istekao.", cs_CZ="Váš datový paket vypršel.", da_DK="Din datapakke er udløbet.", de_DE="Dein Datenpaket ist abgelaufen.", el_GR="Έληξε η ισχύς του πακέτου δεδομένων σας.", en_GB="Your data plan has expired.", es_ES="Su paquete de datos ha caducado.", fi_FI="Datapaketti on vanhentunut.", fr_FR="Votre forfait de données a expiré.", hr_HR="Vaš podatkovni paket je istekao.", hu_HU="Adatcsomagod lejárt.", it_IT="Il pacchetto dati è scaduto.", nl_NL="Je datapakket is verlopen.", no_NO="Datapakken er utløpt.", pl_PL="Twój pakiet danych stracił ważność.", pt_PT="O teu pacote de dados expirou.", ro_RO="Pachetul dumneavoastră de date a expirat.", ru_RU="Срок действия Вашего пакета данных истек.", sk_SK="Váš balík údajov uplynul.", sl_SI="Vaš podatkovni paket je potekel.", sr_RS="Vaš paket podataka je istekao.", sv_SE="Ditt datapaket har löpt ut.", tr_TR="Veri paketinin süresi doldu.", uk_UA="Строк дії вашого пакета даних закінчився.")
texttool_globals_toast___disabled_reason__connectivity_unknown__text = TextObject(bs_BA="Ne postoji podatkovna veza. Pokušajte ponovo kasnije.", cs_CZ="Není žádné datové spojení. Zopakujte prosím později.", da_DK="Ingen dataforbindelse. Forsøg igen senere.", de_DE="Es besteht keine Internetverbindung. Bitte versuche es später\nerneut.", el_GR="Δεν υφίσταται σύνδεση δεδομένων. Προσπαθήστε πάλι αργότερα.", en_GB="There is no internet connection. Please try again later.", es_ES="No hay conexión de datos. Por favor, inténtelo de nuevo más\ntarde.", fi_FI="Ei datayhteyttä. Yritä myöhemmin uudelleen.", fr_FR="Aucune connexion Internet n'est établie. Veuillez réessayer\nultérieurement.", hr_HR="Nema veze za prijenos podataka. Pokušajte ponovno kasnije.", hu_HU="Nincs adatkapcsolat. Próbáld újra később.", it_IT="Nessun collegamento dati. Si prega di riprovare più tardi.", nl_NL="Er is geen dataverbinding. Probeer het later opnieuw.", no_NO="Det er ingen dataforbindelse. Prøv igjen senere.", pl_PL="Brak połączenia danych. Proszę spróbować ponownie później.", pt_PT="Não existe qualquer ligação de dados. Por favor, volta a tentar\nmais tarde.", ro_RO="Nu există conexiune de date. Reîncercaţi mai târziu.", ru_RU="Нет подключения для передачи данных. Повторитепопытку\nпозже.", sk_SK="Nie je vytvorené žiadne prepojenie na prenos údajov. Prosím,\npokúste sa o to znovu neskôr.", sl_SI="Ni podatkovne povezave. Poskusite znova pozneje.", sr_RS="Nema veze za prenos podataka. Pokušajte ponovo kasnije.", sv_SE="Det finns ingen dataanslutning. Försök igen senare.", tr_TR="Veri bağlantısı mevcut değil. Lütfen daha sonra tekrar dene.", uk_UA="Немає підключення до передачі даних. Спробуйте пізніше.")
texttool_globals_toast___disabled_reason__general__text = TextObject(bs_BA="Korištenje podataka nije raspoloživo iz nepoznatih razloga.", cs_CZ="Používání dat je z neznámých důvodů nedostupné.", da_DK="Dataanvendelse ikke tilgængelig af ukendte årsager.", de_DE="Die Datennutzung ist aus unbekannten Gründen nicht verfügbar.", el_GR="Η χρήση δεδομένων δεν είναι διαθέσιμη, για άγνωστους λόγους.", en_GB="It is not possible to use data for unknown reasons.", es_ES="El uso de datos no está disponible por motivos desconocidos.", fi_FI="Datakäyttö ei ole käytettävissä tuntemattomista syistä.", fr_FR="L'utilisation des données n'est pas disponible pour des raisons\ninconnues.", hr_HR="Korištenje podataka iz nepoznatih razloga nije raspoloživo.", hu_HU="Az adathasználat ismeretlen okok miatt nem érhető el.", it_IT="L'utilizzo dei dati non è disponibile per motivi sconosciuti.", nl_NL="Het gebruik van data is om onbekende redenen niet mogelijk.", no_NO="Databruk er av ukjente årsaker ikke tilgjengelig.", pl_PL="Z nieznanych przyczyn, korzystanie z danych jest niedostępne.", pt_PT="Por razões desconhecidas, a utilização de dados não está\ndisponível.", ro_RO="Utilizarea datelor nu este disponibilă, din motive necunoscute.", ru_RU="Использование данных недоступно по неизвестным\nпричинам.", sk_SK="Používanie údajov nie je z neznámych dôvodov k dispozícii.", sl_SI="Uporaba podatkov iz neznanih razlogov ni na voljo.", sr_RS="Korišćenje podataka nije dostupno iz nepoznatih razloga.", sv_SE="Dataanvändning är av okänd anledning inte tillgänglig.", tr_TR="Veri kullanımı, bilinmeyen nedenlerle kullanılamıyor.", uk_UA="Використання даних недоступне через невідомі причини.")
